from pymqd2 import Server, Channel
import base64

def create_vhost(server, vhost_name):
    channel = server.channel()
    channel.queue_declare('amq.virtuals', auto_delete=True)
    channel.exchange_declare('amq.direct', exchange_type='direct')
    channel.queue_bind('amq.virtuals', 'amq.direct', vhost_name)
    channel.queue_delete('amq.virtuals')

def create_user(server, username, password):
    channel = server.channel()
    credentials = base64.b64encode(f'{username}:{password}'.encode()).decode()
    response = channel.call_method('login', 'amqp_login', arguments={
        'user_name': username,
        'password': password,
        'vhost': '/'
    })
    user_id = response['return_value'].body
    return user_id

def set_permissions(server, user_id, vhost_name, readwrite=True):
    channel = server.channel()
    if readwrite:
        permissions = {
            'configure': '.*',
            'write': '.*/\*\*',
            'read': '.*/\*\*'
        }
    else:
        permissions = {
            'configure': '.*',
            'write': ''
        }

    channel.call_method('exchange_declare', arguments={
        'exchange': 'amq.virtualhost.' + vhost_name,
        'type': 'direct'
    })

    for permission in permissions:
        channel.call_method('queue_declare', arguments={'vhost': '/', 'queue': f'amq.permissions.{permission}'})
        channel.basic_publish(exchange='amq.virtualhost.' + vhost_name, routing_key=f'amq.permissions.{permission}', body={
            'user': user_id,
            'vhost': vhost_name,
            'configure': permissions[permission],
        })
        channel.queue_delete(f'amq.permissions.{permission}')

def main():
    server = Server('amqp://guest:guest@localhost')

    # Create or change vhosts as needed
    create_vhost(server, 'app1')
    create_vhost(server, 'app2')

    # Set up users and permissions
    user_id_app1 = create_user(server, 'app1_user', 'password1')
    set_permissions(server, user_id_app1, 'app1')

    user_id_app2 = create_user(server, 'app2_user', 'password2')
    set_permissions(server, user_id_app2, 'app2', readwrite=False)

if __name__ == "__main__":
    main()